import { useEffect, useState } from "react";
import { Routes, Route, Link } from "react-router-dom";

import Counter from "./counter.js";
import Stopwatch from "./stopwatch.js";
import CrystalBall from "./crystal_ball.js";
import DuckHunt from "./duck_hunt.js";
import PizzaBuilder from "./pizza.js";
import TicTacToe from "./tictactoe.js";
import TodoApp from "./todo.js";

const apps = [
  ["🔢", "Counter", "/counter"],
  ["⏱️", "Stopwatch", "/stopwatch"],
  ["🔮", "Crystal Ball", "/crystal-ball"],
  ["🦆", "Duck Hunt", "/duck-hunt"],
  ["🍕", "Pizza Builder", "/pizza"],
  ["⭕", "Tic Tac Toe", "/tictactoe"],
  ["📝", "Todo", "/todo"],
];

export default function App() {

  return (
    <>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/counter" element={<Counter initialCount={100} step={5}/>} />
        <Route path="/stopwatch" element={<Stopwatch />} />
        <Route path="/crystal-ball" element={<CrystalBall />} />
        <Route path="/duck-hunt" element={<DuckHunt />} />
        <Route path="/pizza" element={<PizzaBuilder />} />
        <Route path="/tictactoe" element={<TicTacToe />} />
        <Route path="/todo" element={<TodoApp />} />
      </Routes>
    </>
  );
}

function Home() {
  return (
    <main>
      <h1>React Playground</h1>

      <section>
        {apps.map(([icon, name, path]) => (
			<p>
				<Link to={path}>
				{icon} {name}
				</Link>
			</p>
        ))}
      </section>
    </main>
  );
}
